14,0.15412547,-0.00992430,-0.03196947,0.01839487,-0.04316521,0.07668827,-0.01381128,0.00488773,0.04187581,-0.02983025,0.08301376,0.00334166,0.07330558,-0.07517618,0.01285629,0.00028230,-0.01159505,0.01850510,-0.08376600,0.01388629,-0.06165505,-0.01800995,0.03631727,-0.01246184,-0.04953316,0.03456702,-0.01434496,0.03179015,-0.02946284,-0.05931482,-0.04268917,-0.00702233,0.04024884,0.03047288,0.02224609,0.00755885,-0.10372846,0.02594548,-0.01768807,0.02838197,0.05387620,0.00506334,-0.04599262]',E'Include an `APIRouter` with a custom `prefix`, `tags`, `responses`, and `dependencies` { #include-an-apirouter-with-a-custom-prefix-tags-responses-and-dependencies }\n\n{* ../../docs_src/bigger_applications/app_an_py310/internal/admin.py hl[3] title["app/internal/admin.py"] *}\n\nBut we still want to set a custom `prefix` when including the `APIRouter` so that all its *path operations* start with `/admin`, we want to secure it with the `dependencies` we already have for this project, and we want to include `tags` and `responses`.\n\nWe can declare all that without having to modify the original `APIRouter` by passing those parameters to `app.include_router()`:','{"source": "fastapi", "version": "0.136", "language": "python", "title": "Bigger Applications - Multiple Files { #bigger-applications-multiple-files }", "section_title": "bigger-applications", "url": "https://github.com/fastapi/fastapi/blob/master/docs/en/docs/tutorial/bigger-applications.md", "topics": "fastapi,async,bigger,applications", "categories": "web,python,rest,async"}');
